import React, { useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useDropzone } from 'react-dropzone';
import { uploadResume, analyzeResume } from '../services/resume';
import Card from '../components/UI/Card';
import Button from '../components/UI/Button';
import { 
  DocumentArrowUpIcon, 
  DocumentTextIcon, 
  XMarkIcon,
  ArrowPathIcon,
  CheckCircleIcon,
  ClipboardDocumentIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';

const Analyze = () => {
  const [step, setStep] = useState(1);
  const [file, setFile] = useState(null);
  const [resumeText, setResumeText] = useState('');
  const [jobDescription, setJobDescription] = useState('');
  const [loading, setLoading] = useState(false);
  const [fileName, setFileName] = useState('');
  const navigate = useNavigate();

  const onDrop = useCallback(async (acceptedFiles) => {
    const selectedFile = acceptedFiles[0];
    if (!selectedFile) return;

    setFile(selectedFile);
    setFileName(selectedFile.name);
    
    try {
      setLoading(true);
      const response = await uploadResume(selectedFile);
      setResumeText(response.resumeText);
      setStep(2);
    } catch (error) {
      console.error('Upload failed:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'application/pdf': ['.pdf'],
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document': ['.docx']
    },
    maxFiles: 1,
    maxSize: 10 * 1024 * 1024
  });

  const handleAnalyze = async () => {
    if (!resumeText || !jobDescription) {
      alert('Please provide both resume and job description');
      return;
    }

    try {
      setLoading(true);
      const result = await analyzeResume({
        resumeText,
        jobDescription,
        fileName
      });
      navigate(`/result/${result.analysisId}`);
    } catch (error) {
      console.error('Analysis failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const removeFile = () => {
    setFile(null);
    setResumeText('');
    setFileName('');
    setStep(1);
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 py-8">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent mb-3">
            Resume Analyzer
          </h1>
          <p className="text-gray-600 text-lg">
            Upload your resume and paste a job description to get AI-powered insights
          </p>
        </div>

        {/* Progress Steps */}
        <div className="mb-10">
          <div className="flex items-center justify-center">
            <div className="flex items-center">
              <div className={`flex items-center justify-center w-10 h-10 rounded-full font-semibold transition-all ${
                step >= 1 
                  ? 'bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg' 
                  : 'bg-gray-200 text-gray-500'
              }`}>
                1
              </div>
              <div className={`w-24 h-1 mx-2 transition-all ${
                step >= 2 ? 'bg-gradient-to-r from-indigo-600 to-purple-600' : 'bg-gray-200'
              }`} />
              <div className={`flex items-center justify-center w-10 h-10 rounded-full font-semibold transition-all ${
                step >= 2 
                  ? 'bg-gradient-to-r from-indigo-600 to-purple-600 text-white shadow-lg' 
                  : 'bg-gray-200 text-gray-500'
              }`}>
                2
              </div>
            </div>
          </div>
          <div className="flex justify-center mt-2">
            <div className="flex space-x-32">
              <span className={`text-sm ${step >= 1 ? 'text-indigo-600 font-medium' : 'text-gray-400'}`}>
                Upload Resume
              </span>
              <span className={`text-sm ${step >= 2 ? 'text-indigo-600 font-medium' : 'text-gray-400'}`}>
                Job Description
              </span>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <Card className="overflow-hidden">
          {/* Step 1: Upload Resume */}
          {step === 1 && (
            <div className="py-8">
              {!file ? (
                <div
                  {...getRootProps()}
                  className={`
                    border-2 border-dashed rounded-2xl p-12 text-center cursor-pointer transition-all
                    ${isDragActive 
                      ? 'border-indigo-500 bg-indigo-50' 
                      : 'border-gray-300 hover:border-indigo-400 hover:bg-gray-50'
                    }
                  `}
                >
                  <input {...getInputProps()} />
                  <div className="inline-flex p-4 bg-indigo-100 rounded-full mb-4">
                    <DocumentArrowUpIcon className="h-10 w-10 text-indigo-600" />
                  </div>
                  <h3 className="text-xl font-semibold text-gray-900 mb-2">
                    {isDragActive ? 'Drop your resume here' : 'Upload your resume'}
                  </h3>
                  <p className="text-gray-500 mb-2">
                    Drag & drop or click to select
                  </p>
                  <p className="text-sm text-gray-400">
                    Supported formats: PDF, DOCX (Max 10MB)
                  </p>
                  <Button variant="primary" size="sm" className="mt-6">
                    Choose File
                  </Button>
                </div>
              ) : (
                <div className="flex items-center justify-between p-6 bg-gradient-to-r from-green-50 to-emerald-50 rounded-xl">
                  <div className="flex items-center space-x-4">
                    <div className="bg-green-100 p-3 rounded-xl">
                      <DocumentTextIcon className="h-8 w-8 text-green-600" />
                    </div>
                    <div>
                      <p className="font-semibold text-gray-900">{fileName}</p>
                      <div className="flex items-center space-x-2 mt-1">
                        <CheckCircleIcon className="h-4 w-4 text-green-600" />
                        <p className="text-sm text-green-600">
                          {loading ? 'Processing...' : 'Ready for analysis'}
                        </p>
                      </div>
                    </div>
                  </div>
                  <button
                    onClick={removeFile}
                    className="p-2 hover:bg-white rounded-full transition-colors"
                    disabled={loading}
                  >
                    <XMarkIcon className="h-5 w-5 text-gray-500" />
                  </button>
                </div>
              )}
            </div>
          )}

          {/* Step 2: Job Description */}
          {step === 2 && (
            <div className="py-6">
              <div className="mb-6">
                <div className="flex items-center space-x-2 mb-4">
                  <ClipboardDocumentIcon className="h-5 w-5 text-indigo-600" />
                  <h3 className="text-lg font-semibold text-gray-900">
                    Paste Job Description
                  </h3>
                </div>
                <textarea
                  rows="12"
                  className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all font-mono text-sm"
                  placeholder="Paste the complete job description here...
                  
Example:
We are looking for a Full Stack Developer with experience in React, Node.js, and MongoDB. The ideal candidate should have strong JavaScript skills and knowledge of REST APIs..."
                  value={jobDescription}
                  onChange={(e) => setJobDescription(e.target.value)}
                />
              </div>
              
              <div className="flex justify-end space-x-3">
                <Button
                  variant="secondary"
                  onClick={() => setStep(1)}
                  disabled={loading}
                >
                  Back
                </Button>
                <Button
                  variant="primary"
                  onClick={handleAnalyze}
                  disabled={loading || !jobDescription.trim()}
                  loading={loading}
                  icon={<SparklesIcon className="h-4 w-4" />}
                >
                  {loading ? 'Analyzing...' : 'Analyze Resume'}
                </Button>
              </div>
            </div>
          )}
        </Card>

        {/* Tips Section */}
        <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-white rounded-xl p-4 shadow-sm">
            <div className="flex items-center space-x-2 text-indigo-600 mb-2">
              <DocumentTextIcon className="h-5 w-5" />
              <span className="font-medium">Resume Tips</span>
            </div>
            <p className="text-sm text-gray-600">
              Use a clean, well-formatted resume. PDF format works best for text extraction.
            </p>
          </div>
          <div className="bg-white rounded-xl p-4 shadow-sm">
            <div className="flex items-center space-x-2 text-indigo-600 mb-2">
              <ClipboardDocumentIcon className="h-5 w-5" />
              <span className="font-medium">Job Description</span>
            </div>
            <p className="text-sm text-gray-600">
              Paste the complete job description for the most accurate analysis.
            </p>
          </div>
          <div className="bg-white rounded-xl p-4 shadow-sm">
            <div className="flex items-center space-x-2 text-indigo-600 mb-2">
              <SparklesIcon className="h-5 w-5" />
              <span className="font-medium">AI Analysis</span>
            </div>
            <p className="text-sm text-gray-600">
              Our AI analyzes skills, ATS compatibility, and provides actionable suggestions.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Analyze;
